verb :moveto(target) rx {
  // Restrict $outline_item to outliners and $nowhere (recycle). Reject
  // any attempt to move into an actor's inventory, a room, or another
  // non-outliner container; this is what makes the class not-carryable.
  // Cross-outliner moves are allowed for the item owner, source-outliner
  // owner, or wizard.
  if (target == $nowhere) {
    moveto(this, target);
    return true;
  }
  if (!isa(target, $outliner)) {
    raise { code: "E_NOT_PORTABLE", message: "outline items can only live in an $outliner", value: { item: this, target: target } };
  }
  let here = location(this);
  if (here != target && isa(here, $outliner)) {
    let allowed = false;
    if (this.owner == actor) { allowed = true; }
    if (here.owner == actor) { allowed = true; }
    if (has_flag(actor, "wizard")) { allowed = true; }
    if (!allowed) {
      raise { code: "E_PERM", message: "only the item owner, source outliner owner, or a wizard can move an item across outliners", value: { item: this, from: here, to: target } };
    }
  }
  moveto(this, target);
  return true;
}

verb :recycle() rx {
  // Defensive cleanup: substrate recycle does not fire :exitfunc, so a
  // direct recycle(item) would otherwise leave children pointing at a
  // tombstoned .parent. Detach from the containing outliner first.
  let here = location(this);
  if (isa(here, $outliner)) {
    try { here:_detach_item(this, { emit: true, clear_item: true }); } except err { }
  }
  return true;
}

verb :set_hidden(hidden) rx {
  if (typeof(hidden) != "boolean") {
    if (hidden == 0) { hidden = false; }
    else { if (hidden == 1) { hidden = true; } else { raise { code: "E_INVARG", message: "set_hidden requires a boolean", value: hidden }; } }
  }
  let here = location(this);
  let allowed = false;
  if (isa(here, $outliner)) {
    let actor_loc = location(actor);
    if (actor_loc == here) { allowed = true; }
  }
  if (this.owner == actor) { allowed = true; }
  if (has_flag(actor, "wizard")) { allowed = true; }
  if (!allowed) { raise { code: "E_PERM", message: "cannot toggle hidden on this item", value: this }; }
  this.hidden = hidden;
  return true;
}

verb :set_position(position) rx {
  if (typeof(position) != "number") { raise { code: "E_INVARG", message: "position must be an int", value: position }; }
  if (position < 0) { raise { code: "E_INVARG", message: "position must be >= 0 (0 = transient cleared marker)", value: position }; }
  let here = location(this);
  let allowed = false;
  if (isa(here, $outliner)) {
    if (location(actor) == here) { allowed = true; }
  }
  if (this.owner == actor) { allowed = true; }
  if (has_flag(actor, "wizard")) { allowed = true; }
  if (!allowed) { raise { code: "E_PERM", message: "cannot set item position", value: this }; }
  this.position = floor(position);
  return true;
}

verb :set_parent(new_parent) rx {
  let here = location(this);
  if (!isa(here, $outliner)) { raise { code: "E_INVARG", message: "item is not in an outliner", value: this }; }
  if (new_parent != null) {
    if (!isa(new_parent, $outline_item)) { raise { code: "E_INVARG", message: "parent must be an $outline_item or null", value: new_parent }; }
    if (location(new_parent) != here) { raise { code: "E_INVARG", message: "parent must be in the same outliner", value: new_parent }; }
    if (new_parent == this) { raise { code: "E_CYCLE", message: "item cannot be its own parent", value: this }; }
    let p = new_parent.parent;
    while (p != null) {
      if (p == this) { raise { code: "E_CYCLE", message: "cycle detected", value: { item: this, parent: new_parent } }; }
      p = p.parent;
    }
  }
  let allowed = false;
  if (location(actor) == here) { allowed = true; }
  if (this.owner == actor) { allowed = true; }
  if (has_flag(actor, "wizard")) { allowed = true; }
  if (!allowed) { raise { code: "E_PERM", message: "cannot reparent item", value: this }; }
  this.parent = new_parent;
  return true;
}

verb :look_self() rxd {
  let items = this:list_items();
  let n = length(items);
  let summary = this.name + " has " + to_string(n) + " item";
  if (n != 1) { summary = summary + "s"; }
  summary = summary + ".";
  let focus = null;
  let key = to_string(actor);
  let fmap = this.focus_by_actor;
  if (has(fmap, key)) { focus = fmap[key]; }
  return { id: this, title: this.name, description: this.description, summary: summary, item_count: n, items: items, roster: this:room_roster(), focus: focus };
}

verb :enter() rxd {
  let old = location(actor);
  moveto(actor, this);
  // Reset per-actor state: clear undo slot and reset focus to root.
  let key = to_string(actor);
  let fmap = this.focus_by_actor;
  fmap[key] = null;
  this.focus_by_actor = fmap;
  let umap = this.last_undo;
  if (has(umap, key)) {
    let next = {};
    for k in keys(umap) { if (k != key) { next[k] = umap[k]; } }
    this.last_undo = next;
  }
  let text = actor.name + " opens " + this.name + ".";
  observe({ type: "outliner_entered", source: this, actor: actor, outliner: this, origin: old, text: text, ts: now() });
  if (this.mount_room != null) {
    observe_to_space(this.mount_room, { type: "outliner_activity", source: this.mount_room, outliner: this, actor: actor, text: text, ts: now() });
  }
  return { room: this, roster: this:room_roster() };
}

verb :leave() rxd {
  let dest = actor.home;
  if (this.mount_room != null) { dest = this.mount_room; }
  if (dest == null) { dest = $nowhere; }
  moveto(actor, dest);
  let key = to_string(actor);
  let umap = this.last_undo;
  // Drop this actor's slot AND prune entries for actors no longer present.
  let present_keys = {};
  for a in present_actors(this) { present_keys[to_string(a)] = true; }
  let next_u = {};
  for k in keys(umap) { if (k != key && has(present_keys, k)) { next_u[k] = umap[k]; } }
  this.last_undo = next_u;
  let fmap = this.focus_by_actor;
  let next_f = {};
  for k in keys(fmap) { if (k != key && has(present_keys, k)) { next_f[k] = fmap[k]; } }
  this.focus_by_actor = next_f;
  let text = actor.name + " closes " + this.name + ".";
  observe({ type: "outliner_left", source: this, actor: actor, outliner: this, destination: dest, text: text, ts: now() });
  if (this.mount_room != null) {
    observe_to_space(this.mount_room, { type: "outliner_activity", source: this.mount_room, outliner: this, actor: actor, text: text, ts: now() });
  }
  return { room: dest, roster: this:room_roster() };
}

verb :enterfunc(object) rx {
  if (isa(object, $outline_item)) {
    // Validate parent: if set, must point at a same-outliner item.
    let p = null;
    try { p = object.parent; } except err { p = null; }
    if (p != null) {
      if (!isa(p, $outline_item) || location(p) != this) {
        // Inconsistent — clear to root rather than leaving a dangling parent.
        object:set_parent(null);
        p = null;
      }
    }
    // If position isn't set or is 0, allocate at end of the sibling list.
    let pos = 0;
    try { pos = object.position; } except err { pos = 0; }
    if (typeof(pos) != "number" || pos < 1) {
      let siblings = this:_siblings_ordered(p);
      // Replace any existing entry for this item to avoid double-add on re-enter.
      let cleaned = [];
      for s in siblings { if (s != object) { cleaned = cleaned + [s]; } }
      cleaned = cleaned + [object];
      this:_renumber_siblings(p, cleaned);
    } else {
      // Position present; trust it. (Renumber is the caller's job for moves.)
    }
    let siblings_after = this:_siblings_ordered(p);
    let idx = 0; let i = 1;
    for s in siblings_after { if (s == object) { idx = i - 1; } i = i + 1; }
    let body = "";
    try { body = object:text(); } except err { body = ""; }
    observe({ type: "outline_item_added", source: this, actor: actor, outliner: this, item: object, parent_id: p, index: idx, text: body, ts: now() });
  }
  return true;
}

verb :exitfunc(object) rx {
  if (isa(object, $outline_item)) {
    this:_detach_item(object, { emit: true, clear_item: true });
  }
  return true;
}

verb :list_items() rxd {
  // Depth-first joined view. Group items by parent, sort each group by
  // position, walk from root downward emitting each node followed by its
  // children.
  let by_parent = {};
  for it in contents(this) {
    // Defend against stale refs in contents(this) (E_OBJNF from isa); see
    // `_siblings_ordered` for the same guard.
    let is_item = false;
    try { is_item = isa(it, $outline_item); } except err { is_item = false; }
    if (is_item) {
      let p = null;
      try { p = it.parent; } except err { p = null; }
      let key = "_root";
      if (p != null) { key = to_string(p); }
      let list = [];
      if (has(by_parent, key)) { list = by_parent[key]; }
      list = list + [it];
      by_parent[key] = list;
    }
  }
  // Sort each group by position via the slot trick.
  let sorted = {};
  for k in keys(by_parent) {
    let group = by_parent[k];
    let slot = {};
    let n = 0;
    let unranked = [];
    for it in group {
      let pos = 0;
      try { pos = it.position; } except err { pos = 0; }
      if (typeof(pos) == "number" && pos >= 1) {
        slot[to_string(floor(pos))] = it;
        if (pos > n) { n = floor(pos); }
      } else {
        unranked = unranked + [it];
      }
    }
    let ordered = [];
    let si = 1;
    while (si <= n) {
      if (has(slot, to_string(si))) { ordered = ordered + [slot[to_string(si)]]; }
      si = si + 1;
    }
    for u in unranked { ordered = ordered + [u]; }
    sorted[k] = ordered;
  }
  let out = [];
  let queue = [];
  if (has(sorted, "_root")) {
    let ri = 0;
    for it in sorted["_root"] {
      queue = queue + [{ item: it, parent_id: null, index: ri }];
      ri = ri + 1;
    }
  }
  while (length(queue) > 0) {
    let head = queue[1];
    let rest = [];
    let j = 2;
    while (j <= length(queue)) { rest = rest + [queue[j]]; j = j + 1; }
    queue = rest;
    let cur = head["item"];
    let parent_id = head["parent_id"];
    let idx = head["index"];
    let body = "";
    try { body = cur:text(); } except err { body = ""; }
    let kids_key = to_string(cur);
    let has_children = false;
    let kids = [];
    if (has(sorted, kids_key)) { kids = sorted[kids_key]; has_children = (length(kids) > 0); }
    let hidden = false;
    try { hidden = cur.hidden; } except err { hidden = false; }
    out = out + [{ id: cur, name: cur.name, text: body, parent_id: parent_id, index: idx, hidden: hidden, owner: cur.owner, writers: cur.writers, has_children: has_children }];
    // Insert children at the head of the queue so depth-first order is preserved.
    let child_entries = [];
    let ci = 0;
    for kid in kids {
      child_entries = child_entries + [{ item: kid, parent_id: cur, index: ci }];
      ci = ci + 1;
    }
    let new_queue = [];
    for c in child_entries { new_queue = new_queue + [c]; }
    for r in queue { new_queue = new_queue + [r]; }
    queue = new_queue;
  }
  return out;
}

verb :_siblings_ordered(parent_id) rxd {
  let slot = {};
  let unranked = [];
  let max_pos = 0;
  for it in contents(this) {
    // Stale refs (recycle paths that didn't fully clear contents, or
    // partial-apply leftovers) can sit in `contents(this)`. `isa` on a
    // missing object throws E_OBJNF; wrap so add_item / list_items / etc.
    // keep working.
    let is_item = false;
    try { is_item = isa(it, $outline_item); } except err { is_item = false; }
    if (is_item) {
      let p = null;
      try { p = it.parent; } except err { p = null; }
      if (p == parent_id) {
        let pos = 0;
        try { pos = it.position; } except err { pos = 0; }
        if (typeof(pos) == "number" && pos >= 1) {
          slot[to_string(floor(pos))] = it;
          if (floor(pos) > max_pos) { max_pos = floor(pos); }
        } else {
          unranked = unranked + [it];
        }
      }
    }
  }
  let ordered = [];
  let i = 1;
  while (i <= max_pos) {
    if (has(slot, to_string(i))) { ordered = ordered + [slot[to_string(i)]]; }
    i = i + 1;
  }
  for u in unranked { ordered = ordered + [u]; }
  return ordered;
}

verb :_renumber_siblings(parent_id, ordered) rx {
  let i = 1;
  for it in ordered {
    it:set_position(i);
    i = i + 1;
  }
  return true;
}

verb :_detach_item(item, opts) rx {
  if (typeof(opts) != "map") { opts = {}; }
  let emit = true;
  if (has(opts, "emit")) { emit = opts["emit"]; }
  let clear_item = true;
  if (has(opts, "clear_item")) { clear_item = opts["clear_item"]; }
  let former_parent = null;
  try { former_parent = item.parent; } except err { former_parent = null; }
  // Snapshot direct children of the leaving item, sorted, and reparent them.
  let kids = this:_siblings_ordered(item);
  let parent_siblings = this:_siblings_ordered(former_parent);
  // Build new sibling order under former_parent: existing siblings, with
  // kids spliced in adjacent to where the leaving item sat.
  let item_idx = 0;
  let i = 1;
  for s in parent_siblings { if (s == item) { item_idx = i - 1; } i = i + 1; }
  let new_parent_order = [];
  let cur = 0;
  for s in parent_siblings {
    if (s == item) {
      // Don't include the leaving item.
      for kid in kids { new_parent_order = new_parent_order + [kid]; }
    } else {
      new_parent_order = new_parent_order + [s];
    }
    cur = cur + 1;
  }
  // Reparent kids to former_parent.
  for kid in kids { kid:set_parent(former_parent); }
  // Renumber siblings under former_parent (kids land at the leaving item's slot).
  this:_renumber_siblings(former_parent, new_parent_order);
  if (clear_item) {
    item:set_parent(null);
    item:set_position(0);
  }
  if (emit) {
    observe({ type: "outline_item_removed", source: this, actor: actor, outliner: this, item: item, reparented_to: former_parent, ts: now() });
  }
  return true;
}

verb :_set_undo(actor_obj, record) rx {
  let key = to_string(actor_obj);
  let umap = this.last_undo;
  let next = {};
  // Prune entries for actors no longer present.
  let present_keys = {};
  for a in present_actors(this) { present_keys[to_string(a)] = true; }
  for k in keys(umap) {
    if (k != key && has(present_keys, k)) { next[k] = umap[k]; }
  }
  next[key] = record;
  this.last_undo = next;
  return true;
}

verb :_restore_item(state, _no_store) rx {
  if (typeof(state) != "map") { raise { code: "E_INVARG", message: "_restore_item requires a state map", value: state }; }
  let parent_id = null;
  if (has(state, "parent_id")) { parent_id = state["parent_id"]; }
  if (parent_id != null) {
    if (!isa(parent_id, $outline_item) || location(parent_id) != this || is_recycled(parent_id)) { parent_id = null; }
  }
  let writers = [];
  if (has(state, "writers")) {
    for w in state["writers"] {
      if (!is_recycled(w)) { writers = writers + [w]; }
    }
  }
  let item_name = "";
  if (has(state, "name")) { item_name = state["name"]; }
  let item_desc = "";
  if (has(state, "description")) { item_desc = state["description"]; }
  let item_owner = actor;
  if (has(state, "owner")) {
    if (!is_recycled(state["owner"])) { item_owner = state["owner"]; }
  }
  let body = "";
  if (has(state, "text")) { body = state["text"]; }
  let hidden = false;
  if (has(state, "hidden")) { hidden = state["hidden"]; }
  let captured_index = 0;
  if (has(state, "index")) { captured_index = state["index"]; }
  // Create the new item.
  let opts = { owner: item_owner, name: item_name, description: item_desc, location: this };
  let item = create($outline_item, opts);
  item:set_parent(parent_id);
  // Insert into parent's siblings at captured_index (clamped).
  let siblings = this:_siblings_ordered(parent_id);
  // Filter out item if enterfunc already placed it via renumber.
  let without = [];
  for s in siblings { if (s != item) { without = without + [s]; } }
  let target_idx = captured_index;
  if (target_idx < 0) { target_idx = 0; }
  if (target_idx > length(without)) { target_idx = length(without); }
  let new_order = [];
  let cur = 0;
  let inserted = false;
  for s in without {
    if (cur == target_idx && !inserted) {
      new_order = new_order + [item];
      inserted = true;
    }
    new_order = new_order + [s];
    cur = cur + 1;
  }
  if (!inserted) { new_order = new_order + [item]; }
  this:_renumber_siblings(parent_id, new_order);
  item:set_hidden(hidden);
  for w in writers { item:add_writer(w); }
  item:set_text(body);
  // Restore captured children: move each back under the new item at its captured rank.
  if (has(state, "children")) {
    let kid_idx = 0;
    for entry in state["children"] {
      let kid = entry["item"];
      if (!is_recycled(kid)) {
        if (isa(kid, $outline_item)) {
          try { this:move_item(kid, item, kid_idx, true); } except err { }
        }
      }
      kid_idx = kid_idx + 1;
    }
  }
  if (!_no_store) {
    this:_set_undo(actor, { verb: "remove_item", args: [item] });
  }
  return item;
}

verb :add_item(text, parent_id, index, _no_store) rx {
  if (typeof(text) != "string") { raise { code: "E_INVARG", message: "add_item requires text", value: text }; }
  if (text == "") { raise { code: "E_INVARG", message: "add_item requires non-empty text", value: text }; }
  // Default parent: caller's focus when parent_id is null.
  let p = parent_id;
  if (p == null) {
    let key = to_string(actor);
    let fmap = this.focus_by_actor;
    if (has(fmap, key)) { p = fmap[key]; }
  }
  if (p != null) {
    if (!isa(p, $outline_item)) { raise { code: "E_INVARG", message: "parent must be an outline item", value: p }; }
    if (location(p) != this) { raise { code: "E_INVARG", message: "parent is not in this outliner", value: p }; }
  }
  let siblings = this:_siblings_ordered(p);
  let n = length(siblings);
  let idx = index;
  if (typeof(idx) != "number") { idx = n; }
  idx = floor(idx);
  if (idx < 0 || idx > n) { raise { code: "E_INDEX", message: "index out of range", value: { index: idx, n: n } }; }
  let item = create($outline_item, { owner: actor, location: this, name: "" });
  item:set_parent(p);
  // Build new ordering with item at idx.
  let new_order = [];
  let cur = 0;
  let inserted = false;
  for s in siblings {
    if (cur == idx && !inserted) { new_order = new_order + [item]; inserted = true; }
    new_order = new_order + [s];
    cur = cur + 1;
  }
  if (!inserted) { new_order = new_order + [item]; }
  this:_renumber_siblings(p, new_order);
  item:set_text(text);
  observe({ type: "outline_item_added", source: this, actor: actor, outliner: this, item: item, parent_id: p, index: idx, text: text, ts: now() });
  if (!_no_store) {
    this:_set_undo(actor, { verb: "remove_item", args: [item] });
  }
  return item;
}

verb :set_item_text(item, text, _no_store) rx {
  if (!isa(item, $outline_item)) { raise { code: "E_NO_ITEM", message: "not an outline item", value: item }; }
  if (location(item) != this) { raise { code: "E_NO_ITEM", message: "item is not in this outliner", value: item }; }
  let old_text = "";
  try { old_text = item.text; } except err { old_text = ""; }
  item:set_text(text);
  if (!_no_store) {
    this:_set_undo(actor, { verb: "set_item_text", args: [item, old_text] });
  }
  return true;
}

verb :move_item(item, new_parent_id, index, _no_store) rx {
  if (!isa(item, $outline_item)) { raise { code: "E_NO_ITEM", message: "not an outline item", value: item }; }
  if (location(item) != this) { raise { code: "E_NO_ITEM", message: "item is not in this outliner", value: item }; }
  if (new_parent_id != null) {
    if (!isa(new_parent_id, $outline_item)) { raise { code: "E_INVARG", message: "parent must be outline item or null", value: new_parent_id }; }
    if (location(new_parent_id) != this) { raise { code: "E_INVARG", message: "parent is in a different outliner", value: new_parent_id }; }
    if (new_parent_id == item) { raise { code: "E_CYCLE", message: "item cannot be its own parent", value: item }; }
    let p = new_parent_id.parent;
    while (p != null) {
      if (p == item) { raise { code: "E_CYCLE", message: "cycle detected", value: { item: item, parent: new_parent_id } }; }
      p = p.parent;
    }
  }
  let old_parent = item.parent;
  let old_siblings = this:_siblings_ordered(old_parent);
  let old_idx = 0; let i = 1;
  for it in old_siblings { if (it == item) { old_idx = i - 1; } i = i + 1; }
  let cross = (new_parent_id != old_parent);
  let dest_siblings = old_siblings;
  if (cross) { dest_siblings = this:_siblings_ordered(new_parent_id); }
  // Compute dest length excluding the item if it's already in dest.
  let dest_without = [];
  for it in dest_siblings { if (it != item) { dest_without = dest_without + [it]; } }
  let max_idx = length(dest_without);
  let idx = index;
  if (typeof(idx) != "number") { idx = max_idx; }
  idx = floor(idx);
  if (idx < 0 || idx > max_idx) { raise { code: "E_INDEX", message: "index out of range", value: { index: idx, max: max_idx } }; }
  // No-op detect.
  if (!cross && idx == old_idx) { return false; }
  // Build new dest order.
  let new_dest = [];
  let cur = 0;
  let inserted = false;
  for it in dest_without {
    if (cur == idx && !inserted) { new_dest = new_dest + [item]; inserted = true; }
    new_dest = new_dest + [it];
    cur = cur + 1;
  }
  if (!inserted) { new_dest = new_dest + [item]; }
  item:set_parent(new_parent_id);
  this:_renumber_siblings(new_parent_id, new_dest);
  if (cross) {
    let old_remaining = [];
    for it in old_siblings { if (it != item) { old_remaining = old_remaining + [it]; } }
    this:_renumber_siblings(old_parent, old_remaining);
  }
  observe({ type: "outline_item_moved", source: this, actor: actor, outliner: this, item: item, from_parent: old_parent, from_index: old_idx, to_parent: new_parent_id, to_index: idx, ts: now() });
  if (!_no_store) {
    this:_set_undo(actor, { verb: "move_item", args: [item, old_parent, old_idx] });
  }
  return true;
}

verb :reorder_item(item, index, _no_store) rx {
  if (!isa(item, $outline_item)) { raise { code: "E_NO_ITEM", message: "not an outline item", value: item }; }
  if (location(item) != this) { raise { code: "E_NO_ITEM", message: "item is not in this outliner", value: item }; }
  let parent_id = item.parent;
  let siblings = this:_siblings_ordered(parent_id);
  let old_idx = 0; let i = 1;
  for it in siblings { if (it == item) { old_idx = i - 1; } i = i + 1; }
  let without = [];
  for it in siblings { if (it != item) { without = without + [it]; } }
  let max_idx = length(without);
  let idx = index;
  if (typeof(idx) != "number") { raise { code: "E_INVARG", message: "reorder_item requires an index", value: idx }; }
  idx = floor(idx);
  if (idx < 0 || idx > max_idx) { raise { code: "E_INDEX", message: "index out of range", value: { index: idx, max: max_idx } }; }
  if (idx == old_idx) { return false; }
  let new_order = [];
  let cur = 0;
  let inserted = false;
  for it in without {
    if (cur == idx && !inserted) { new_order = new_order + [item]; inserted = true; }
    new_order = new_order + [it];
    cur = cur + 1;
  }
  if (!inserted) { new_order = new_order + [item]; }
  this:_renumber_siblings(parent_id, new_order);
  observe({ type: "outline_item_reordered", source: this, actor: actor, outliner: this, item: item, parent_id: parent_id, from_index: old_idx, to_index: idx, ts: now() });
  if (!_no_store) {
    this:_set_undo(actor, { verb: "reorder_item", args: [item, old_idx] });
  }
  return true;
}

verb :hide(item, hidden, _no_store) rx {
  if (!isa(item, $outline_item)) { raise { code: "E_NO_ITEM", message: "not an outline item", value: item }; }
  if (location(item) != this) { raise { code: "E_NO_ITEM", message: "item is not in this outliner", value: item }; }
  if (typeof(hidden) != "boolean") {
    if (hidden == 0) { hidden = false; } else { if (hidden == 1) { hidden = true; } else { raise { code: "E_INVARG", message: "hide requires a boolean", value: hidden }; } }
  }
  let was = false;
  try { was = item.hidden; } except err { was = false; }
  item:set_hidden(hidden);
  observe({ type: "outline_item_hidden", source: this, actor: actor, outliner: this, item: item, hidden: hidden, ts: now() });
  if (!_no_store) {
    this:_set_undo(actor, { verb: "hide", args: [item, was] });
  }
  return true;
}

verb :hide_command(item) rx {
  let target = item;
  if (typeof(target) == "string") { target = $match:match_object(target, this); }
  if (target == $failed_match || target == $ambiguous_match) { raise { code: "E_INVARG", message: "hide which item?", value: item }; }
  return this:hide(target, true);
}

verb :remove_item(item, _no_store) rx {
  if (!isa(item, $outline_item)) { raise { code: "E_NO_ITEM", message: "not an outline item", value: item }; }
  if (location(item) != this) { raise { code: "E_NO_ITEM", message: "item is not in this outliner", value: item }; }
  if (item.owner != actor && !has_flag(actor, "wizard")) { raise { code: "E_PERM", message: "only the item author or a wizard can remove it; outliner owners use eject", value: item }; }
  // Capture state for undo.
  let captured = this:_capture_item(item);
  recycle(item);
  if (!_no_store) {
    this:_set_undo(actor, { verb: "_restore_item", args: [captured] });
  }
  return true;
}

verb :eject_item(item) rx {
  if (!isa(item, $outline_item)) { raise { code: "E_NO_ITEM", message: "not an outline item", value: item }; }
  if (location(item) != this) { raise { code: "E_NO_ITEM", message: "item is not in this outliner", value: item }; }
  if (this.owner != actor && !has_flag(actor, "wizard")) { raise { code: "E_PERM", message: "only the outliner owner or a wizard can eject items", value: item }; }
  // No undo for curator path.
  recycle(item);
  return true;
}

verb :_capture_item(item) rxd {
  let siblings = this:_siblings_ordered(item.parent);
  let idx = 0; let i = 1;
  for it in siblings { if (it == item) { idx = i - 1; } i = i + 1; }
  let kids = this:_siblings_ordered(item);
  let kid_entries = [];
  for kid in kids {
    let kpos = 0;
    try { kpos = kid.position; } except err { kpos = 0; }
    kid_entries = kid_entries + [{ item: kid, position: kpos }];
  }
  let text = "";
  try { text = item.text; } except err { text = ""; }
  let writers = [];
  try { writers = item.writers; } except err { writers = []; }
  let hidden = false;
  try { hidden = item.hidden; } except err { hidden = false; }
  return {
    text: text,
    name: item.name,
    description: item.description,
    writers: writers,
    hidden: hidden,
    owner: item.owner,
    parent_id: item.parent,
    index: idx,
    children: kid_entries
  };
}

verb :undo() rx {
  let key = to_string(actor);
  let umap = this.last_undo;
  if (!has(umap, key)) { return false; }
  let record = umap[key];
  if (record == null) { return false; }
  // Clear slot before dispatch so the dispatched verb doesn't re-write it.
  let next = {};
  for k in keys(umap) { if (k != key) { next[k] = umap[k]; } }
  this.last_undo = next;
  let verb_name = record["verb"];
  let inverse_args = record["args"];
  // Append the no-store marker so dispatched composers skip slot writes.
  let full_args = [];
  for a in inverse_args { full_args = full_args + [a]; }
  full_args = full_args + [true];
  let result = null;
  try { result = dispatch(this, verb_name, full_args); } except err {
    observe({ type: "outline_undone", source: this, actor: actor, outliner: this, inverse_op: record, error: err, ts: now() });
    return false;
  }
  observe({ type: "outline_undone", source: this, actor: actor, outliner: this, inverse_op: record, ts: now() });
  return result;
}

verb :focus_on(item) rx {
  let target = null;
  if (item != null) {
    if (!isa(item, $outline_item)) { raise { code: "E_NO_ITEM", message: "focus target must be null or an outline item", value: item }; }
    if (location(item) != this) { raise { code: "E_NO_ITEM", message: "focus target is not in this outliner", value: item }; }
    target = item;
  }
  let key = to_string(actor);
  let fmap = this.focus_by_actor;
  let next = {};
  let present_keys = {};
  for a in present_actors(this) { present_keys[to_string(a)] = true; }
  for k in keys(fmap) {
    if (k != key && has(present_keys, k)) { next[k] = fmap[k]; }
  }
  next[key] = target;
  this.focus_by_actor = next;
  observe({ type: "outline_focus_changed", source: this, actor: actor, to: actor, outliner: this, item: target, ts: now() });
  return target;
}

verb :focus_command(item) rx {
  let target = item;
  if (typeof(target) == "string") { target = $match:match_object(target, this); }
  if (target == $failed_match || target == $ambiguous_match) { raise { code: "E_INVARG", message: "focus which item?", value: item }; }
  return this:focus_on(target);
}

verb :add(text) rx {
  if (typeof(text) != "string") { raise { code: "E_INVARG", message: "add requires text", value: text }; }
  text = str_trim(text);
  if (text == "") { raise { code: "E_INVARG", message: "add requires non-empty text", value: text }; }
  return this:add_item(text);
}
